import requests
import json

class RabbitMQConfig:
    def __init__(self, host='localhost', port=15672, username='guest', password='guest'):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.base_url = f"http://{self.host}:{self.port}/api"
        
    def create_vhost(self, vhost_name):
        """Create a virtual host"""
        url = f"{self.base_url}/vhosts/{vhost_name}"
        response = requests.put(url, auth=(self.username, self.password))
        if response.status_code == 201:
            print(f"Created vhost: {vhost_name}")
        else:
            print(f"Failed to create vhost {vhost_name}: {response.text}")
            
    def delete_vhost(self, vhost_name):
        """Delete a virtual host"""
        url = f"{self.base_url}/vhosts/{vhost_name}"
        response = requests.delete(url, auth=(self.username, self.password))
        if response.status_code == 204:
            print(f"Deleted vhost: {vhost_name}")
        else:
            print(f"Failed to delete vhost {vhost_name}: {response.text}")
            
    def create_user(self, username, password, tags=""):
        """Create a user"""
        url = f"{self.base_url}/users/{username}"
        data = {
            "password": password,
            "tags": tags
        }
        response = requests.put(url, auth=(self.username, self.password), json=data)
        if response.status_code == 201:
            print(f"Created user: {username}")
        else:
            print(f"Failed to create user {username}: {response.text}")
            
    def delete_user(self, username):
        """Delete a user"""
        url = f"{self.base_url}/users/{username}"
        response = requests.delete(url, auth=(self.username, self.password))
        if response.status_code == 204:
            print(f"Deleted user: {username}")
        else:
            print(f"Failed to delete user {username}: {response.text}")
            
    def set_permissions(self, username, vhost_name, configure=".*", write=".*", read=".*"):
        """Set permissions for a user on a vhost"""
        url = f"{self.base_url}/permissions/{vhost_name}/{username}"
        data = {
            "configure": configure,
            "write": write,
            "read": read
        }
        response = requests.put(url, auth=(self.username, self.password), json=data)
        if response.status_code == 204:
            print(f"Set permissions for user {username} on vhost {vhost_name}")
        else:
            print(f"Failed to set permissions for user {username} on vhost {vhost_name}: {response.text}")

